#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int count_trees(int n, int d) {
    int* dp = (int*) malloc((n + 1) * sizeof(int));
    dp[0] = 1;
    for (int i = 1; i <= n; i++) {
        for (int j = d; j <= i; j++) {
            dp[i] = (dp[i] + dp[i - j]) % MOD;
        }
    }
    int result = dp[n];
    free(dp);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n, d;
        scanf("%d %d", &n, &d);
        printf("Case %d: %d\n", t + 1, count_trees(n, d));
    }
    return 0;
}

